svg.script:
(function() {
  var svg  = document.getElementById('root');
  var ca   = document.getElementById('ca');
  var isDark = false;

  /* §3 — .ready gate: last animation ends at (0.40 + 1.10)*1000 + 100 = 1600ms */
  setTimeout(function() { ca.classList.add('ready'); }, 1600);

  /* §4 — Series hover: JS .hovering/.active on .bw */
  var bws = Array.prototype.slice.call(ca.querySelectorAll('.bw'));
  bws.forEach(function(bw) {
    bw.addEventListener('mouseenter', function() {
      ca.classList.add('hovering');
      bw.classList.add('active');
    });
    bw.addEventListener('mouseleave', function() {
      bw.classList.remove('active');
      ca.classList.remove('hovering');
    });
  });

  /* §4 — Dot hover: hit targets are in #dot-hit-layer, painted above all polygons.
     Each circle's id maps to a bubble via id + '-bub'. */
  var hitLayer = document.getElementById('dot-hit-layer');
  var dws = Array.prototype.slice.call(hitLayer.querySelectorAll('circle'));
  dws.forEach(function(dw) {
    var bubId = dw.id + '-bub';
    var bub = document.getElementById(bubId);
    dw.addEventListener('mouseenter', function() {
      if (bub) bub.style.opacity = '1';
    });
    dw.addEventListener('mouseleave', function() {
      if (bub) bub.style.opacity = '';
    });
  });

  /* §2 — Dark mode: isDark boolean, CSS handles palette swap automatically */
  function setMode(wantDark) {
    if (wantDark === isDark) return;
    isDark = wantDark;
    var thumb = document.getElementById('tthumb');
    var lbl   = document.getElementById('tlabel');
    if (wantDark) {
      svg.classList.add('dark');
      if (thumb) thumb.setAttribute('cx', '52');
      if (lbl)   lbl.textContent = 'Light';
    } else {
      svg.classList.remove('dark');
      if (thumb) thumb.setAttribute('cx', '16');
      if (lbl)   lbl.textContent = 'Dark';
    }
  }

  document.getElementById('dark-toggle').addEventListener('click', function() {
    setMode(!isDark);
  });
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                               { thumb.setAttribute('cx','16'); lbl.textContent='Print';  }
  });

  window.setMode = setMode;
  window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'setMode') setMode(e.data.dark);
  });
  setMode(window.location.href.indexOf('theme=dark') !== -1);
})();
